var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 보안국 청사 지하 조사실\\n<color=#ffd34c>레버넌트</color>, 반역죄 조사 중\\n조사 시작 후 ██시간째.","JPN":"グロニア保安局庁舎、地下調査室\\n<color=#ffd34c>レヴナント</color>、反逆罪調査中\\n調査開始から██時間経過","ENG":"Gronia Department of National Security’s Underground Interrogation Room\\n<color=#ffd34c>Revenant</color>, ██ hours after the start of the investigation.","TWN":"格羅尼亞安全局地下調查室\\n<color=#ffd34c>亡靈</color>，叛國罪調查中\\n調查開始後經過██小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"ENG":"The following brown colored comments are written by Harrison"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_DIVE_02"},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"콜록……!","JPN":"ゲホッ……！","ENG":"*Cough!*","TWN":"咳咳……！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"사람이 말하는데 졸고 있으면 안 되지, 레버넌트.","JPN":"人が話してる最中にうとうとするとは感心しないな、レヴナント。","ENG":"It’s quite rude to doze off when someone is talking, Revenant.","TWN":"人家在說話，你怎麼可以睡著呢，亡靈。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……다 국장님 덕분이죠. 여기 온 뒤로 한숨도 못 잤으니까요.","JPN":"……すべて局長のおかげです。ここに来てから一睡もできませんでしたから。","ENG":"...That is all thanks to you. I haven’t been able to sleep at all ever since I was brought here.","TWN":"……還不是拜部長所賜，我來到這裡後眼睛完全沒閉過。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"물벼락을 맞으니 정신이 좀 드나?","JPN":"水を浴びて、少しは目が覚めたか？","ENG":"Recovering your senses after getting hit by water?","TWN":"潑完水有比較清醒一點吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그렇군. 나도 자네를 오랫동안 봐 오면서 이런 식으로 대하게 될 줄은 몰랐어.","JPN":"そうだな。君とは長い付き合いになるが、私もこんな風に対することになるとは思わなかった。","ENG":"I see. Knowing each other for so long, even I never thought things would come to this.","TWN":"我認識你這麼久，沒想到會有像這樣審問你的一天。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"다시 한 번 묻지.","JPN":"もう一度聞こう。","ENG":"I shall ask again.","TWN":"我再問你一次！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그날…… 파레마에서 자크를 사살한 이유가 뭔가?","JPN":"あの日……パレマでジャックを射殺した理由は何だ？","ENG":"That day... In Parema, why did you kill Jacques?","TWN":"那天……你在波雷馬射殺札克的理由是什麼？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……몇 번이나 말씀드렸을 텐데요. 저를 노린 저격에 대신 맞은 거라고.","JPN":"……何度も言ったはずです。私を狙った狙撃の代わりに撃たれたんだと。","ENG":"...How many times do I need to tell you. I was the actual target and he was hit instead of me.","TWN":"……到底要我說幾次，他是我的替死鬼，狙擊手原本的目標是我。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저격수를 찾아서 물어 보세요. 지금 수도에 와 있으니까요.","JPN":"スナイパーを探して聞いてみてください。今首都に来ていますから。","ENG":"Find the sniper and ask her. She’s in the capital right now.","TWN":"不信你自己去問找狙擊手問吧，反正你現在人就在首都。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"반군들을 이용하는 위험인물입니다. 내버려 두면 무슨 짓을 저지를지 몰라요.","JPN":"反乱軍を利用している危険人物です。放っておいたら何をしでかすかわかりません。","ENG":"She’s a dangerous figure. She is using the rebels for her own ends. If you leave her alone, there’s no telling what she could do.","TWN":"而且她可是會利用叛軍的危險人物，放著不管不知道會做出什麼事來。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래? 처음부터 목격자들을 없애려고 자네가 끌어들인 강경파 인물이 아니라?","JPN":"本当か？　最初から目撃者を消すために、君が引き込んだ強硬派の人物ではなく？","ENG":"Is that so? Or is it someone from the hardliners you dragged into your plot in order to help eliminate witnesses?","TWN":"是嗎？她不是你用來將目擊者滅口的強硬派人士嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 애초에 절 죽이려고 수도까지 쫓아오지도 않았겠죠.","JPN":"だったら初めから私を殺すために首都まで追ってこなかったでしょう。","ENG":"If that were the case she wouldn’t have chased me all the way to the capital to kill me.","TWN":"如果是這樣，那她幹嘛還追到首都來要殺我？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"도심에서 벌어진 난전에 대해서는 보고 받았어.","JPN":"都心で起こった乱戦については報告を受けている。","ENG":"I’ve already been briefed about what occurred in the city.","TWN":"關於在市中心發生的混戰，我是有收到報告。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하지만 지금은 그것도 자작극이 아닐지 의심스러운 판국이야.","JPN":"だが今はそれも自作自演ではないか疑わしい状況だ。","ENG":"But now I cannot help but wonder if this was also part of your plot.","TWN":"但我現在也很懷疑，那是不是你自導自演的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……믿음을 가져 보시죠, 국장님.","JPN":"……信じてみてはどうですか、局長。","ENG":"... Trust me, Chief.","TWN":"……你相信我吧，部長！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"미안하군. 나는 남을 속이는 사람이지, 속는 사람이 되어선 안 돼.","JPN":"悪いな。私は人を騙す方で、騙される側にはなれないんだ。","ENG":"My apologies. I'm the one to deceive, never the one to be deceived.","TWN":"抱歉，從來就只有我能騙人，別人不能騙我。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그리고 자네는 나를 이미 한 번 멋지게 속였어.","JPN":"そして君はすでに私を見事に騙した。","ENG":"Furthermore, you've already masterfully deceived me once.","TWN":"再說你已經成功騙過我一次。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자크의 부검 소견이다. 당일 자리를 비웠던 아들 놈이 시신을 수습해 뒀었지.","JPN":"ジャックの解剖所見書だ。当日席を外していた息子が遺体を収拾しておいたんだ。","ENG":"I am referring to Jacques’ autopsy. His son, who was away at the time, recovered the body that very day.","TWN":"這是札克的驗屍報告，當天原本不在的兒子，後來有去替札克收屍。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"부검의 말로는 저격총의 탄도와 구경을 고려하면 입을 수 없는 총상이라더군.","JPN":"解剖医曰く、狙撃銃の弾道と口径を考えるとあり得ない銃傷らしいな。","ENG":"The results of the autopsy report that upon analyzing the wound, the trajectory and size of the bullet do not match that of a sniper.","TWN":"根據驗屍報告，以狙擊槍的彈道和口徑來看，札克身上的槍傷不可能是狙擊手造成的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하지만 자네가 소매에 숨기고 다니던 권총과는 정확하게 들어맞아.","JPN":"だが君が袖に隠し持っていた拳銃とは正確に一致する。","ENG":"But rather fit the pistol that you hide in your sleeve.","TWN":"但你藏在袖子裡的槍卻是完全吻合的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네는 저격수를 발견한 순간 자크를 쐈어. 저격총의 총성에 묻어 갈 생각이었지.","JPN":"君はスナイパーを見つけた瞬間にジャックを撃った。狙撃銃の銃声に便乗するつもりだっただろう。","ENG":"You shot Jacques the moment you discovered the sniper. You saw the sniper as the perfect excuse.","TWN":"你在發現狙擊手的瞬間便射殺札克，因為你打算用狙擊手的槍聲來作為掩護。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자크가 교전에 휘말려 죽었다면 직접 사살한 것보다 처벌이 훨씬 가벼워지니 말이야.","JPN":"ジャックが交戦に巻き込まれ死んだとあれば、直接射殺した場合より処罰がずっと軽くなるからな。","ENG":"If Jacques so happened to die in a firefight, the punishment would be light in comparison with you directly shooting him yourself.","TWN":"因為札克因意外而亡的懲罰，會比你直接射殺他來得輕。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래서 제가 강경파 반군과 결탁해서 자크를 죽였다는 건가요?","JPN":"それで私が強硬派の反乱軍と組んでジャックを殺したと言うんですか？","ENG":"So you think I colluded with the hardliner rebels to kill Jacques?","TWN":"所以我才要勾結強硬派叛軍暗殺札克嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"재미있는 가설이네요. 은퇴하고 소설가 하셔도 되겠어요.","JPN":"面白い仮説ですね。引退後、小説家になったらどうですか。","ENG":"Quite the hypothesis. You should retire and become a writer.","TWN":"想像力真是豐富，等你退休後應該可以去當小說家吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>파레마 건은 불운한 사고였다.</color> 제가 할 말은 그것뿐입니다.","JPN":"<color=#ffd34c>パレマの件は不運な事故だった。</color>私から言えるのはそれだけです。","ENG":"<color=#ffd34c>The Parema incident was just an unfortunate accident.</color> That’s all I have to say.","TWN":"<color=#ffd34c>波雷馬的事是倒楣的意外。</color>除此之外我無話可說。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트! 계속 그딴 식으로 상관을 기만할 건가?","JPN":"レヴナント！　そうやって上司を欺き続けるつもりなのか？","ENG":"Revenant! Are you really going to keep lying to your superior like this?","TWN":"亡靈！你還要這樣繼續欺瞞長官嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"국장님이야말로 이상하시네요.","JPN":"局長こそおかしいですね。","ENG":"You’re the one being unreasonable.","TWN":"部長你才很奇怪！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저도 우리나라 법은 어느 정도 알고 있습니다. 국장님의 가설이 사실이라도 반역죄로 연행될 정도는 아니에요.","JPN":"私もこの国の法ならある程度知ってます。局長の仮説が事実であっても、反逆罪で連行されるほどではありません。","ENG":"I know enough about the laws of our country to know that even if your hypothesis were true, it’s still not enough to lock me up for treason.","TWN":"我對我們國家的法律也是略知一二，就算你的假設是成立的，也不至於以叛國罪的名義逮捕我。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니면, 자크를 납치하려던 이유가 <color=#ffd34c>평소</color>와는 달랐던 건가요?","JPN":"それとも、ジャックを拉致しようとした理由が<color=#ffd34c>いつも</color>とは違ってたんですか？","ENG":"Or was there <color=#ffd34c>another</color> reason you tried to kidnap him?","TWN":"難道，這次綁架札克的理由和<color=#ffd34c>平常</color>不一樣嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"지금은 심문 중이야. 내가 묻는 말에 대답만 해.","JPN":"今は尋問中だ。私が聞くことにだけ答えろ。","ENG":"This is my interrogation. I’m the one asking the questions.","TWN":"現在是我在問你話！你只需要回答我的問題！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 이렇게 된 거 들어야겠어요.","JPN":"いいえ。こうなった以上聞かないわけにはいきません。","ENG":"No. I need to know.","TWN":"不！既然如此我更要問清楚！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"요제프 클림트는 누굽니까? 정부는 왜 건국제에 혈안이 되어 있죠?","JPN":"ヨセフ・クリムトとは誰ですか？　政府はどうして建国記念日に血眼になっているんですか？","ENG":"Who is Yosef Klimt, really? And why is the government so obsessed with National Foundation Day?","TWN":"約瑟·克里姆是誰？為什麼政府這麼重視國慶日？"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"대체 상부는 건국제에서 무슨 일을 하려는 겁니까?","JPN":"上層部は建国記念日にいったい何をするつもりなんですか？","ENG":"What the hell do the higher ups have planned for it?","TWN":"上面的人到底打算在國慶日做什麼？"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네가 말했지. 반군들은 여전히 점령지에서 왕 노릇을 하고 있다고.","JPN":"君が言っていたな。反乱軍は今でも占領地で王様ごっこをしていると。","ENG":"You yourself said it before. The rebels are still like kings in the occupied territories.","TWN":"你之前不是也說過，叛軍現在還在佔領的地方據地為王嗎？"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그리고 자크는, 관리실패 이전부터 반정부 단체에서 활동했던 원로 인사였지.","JPN":"そしてジャックは、管理失敗の前から反政府団体で活動していた元老だった。","ENG":"And Jacques was a senior member of the anti-government organization before the Administration Failure occurred.","TWN":"而札克是在管理失敗之前，就參與在反政府團體當中的元老級人物。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요. 설마…….","JPN":"待ってください。まさか……","ENG":"Wait. Do you mean...","TWN":"等等，該不會……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래. 고만고만한 <color=#ffd34c>왕</color>들을 설득할 수 있는 인물이었어.","JPN":"そうだ。似たり寄ったりの<color=#ffd34c>王</color>たちを説得できる人物だったんだ。","ENG":"Correct. He was a figure that could have persuaded those so-called <color=#ffd34c>kings</color>.","TWN":"沒錯，他是可以遊說那些<color=#ffd34c>王</color>的人物。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"정부가 반군들과 평화 협정을 맺으려고 한 건가요?","JPN":"政府が反乱軍と平和協定を結ぼうとしたんですか？","ENG":"So the government was trying to make a peace deal with the rebels?","TWN":"政府是想和叛軍談和嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"자크를 납치해 오라고 했던 이유는, 그 작자를 회유하기 위해서였고?","JPN":"ジャックを拉致しろと言った理由は、あの男を手なずけるため？","ENG":"The reason you asked me to kidnap Jacques, was so we could bring him to our side?","TWN":"之所以要綁架札克，是因為想攏絡他？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……은밀하게 진행되었던 사안이었어.","JPN":"……内密に進められていた案件だった。","ENG":"...It was a top secret matter.","TWN":"……這件事是機密，"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"나 역시 그 건으로 문책 받을 때 들은 내용이야.","JPN":"私もその件で問責された時に聞いたことだ。","ENG":"I did not hear of it either until I was reprimanded for the mission’s failure.","TWN":"我也是因為那件事被究責時才知道的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아……. 아하, 그래서…… 그래서 저랑 강경파 반군을 엮으려고 하셨군요.","JPN":"あ……へぇ、なるほど……それで私と強硬派の反乱軍を結びつけようとしたんですね。","ENG":"Ah... A-ha, So... That’s why you think I’m with the hardliner rebels.\\n\\n","TWN":"哈……哈哈……所以才想把我和強硬派叛軍扯在一起嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"반군들과……. 하, 하하……! 아하하하하하하……!!","JPN":"反乱軍と……は、はは……！　あはははははは……！！","ENG":"With the rebels... Ha, ha ha...! Aha ha ha...!!","TWN":"和叛軍……哈哈……！哈哈哈哈哈……！！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"협정은 건국절 날 논의될 예정이다.","JPN":"協定は建国記念日に議論される予定だ。","ENG":"The agreement is to be discussed on National Foundation Day.","TWN":"談和這件事預計會在國慶日當天進行，"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"평화와 화해를 기원하던 자네 어머니의 곡이 연주되는 가운데 말이야.","JPN":"平和と和解を望んでいた君の母親の曲が演奏される中でな。","ENG":"While your mother's song, that wishes for peace and reconciliation, plays.","TWN":"就在演奏你媽媽那首祈禱和平與和解的曲子時。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"문제는 저쪽에서 자크의 죽음에 대해 냄새를 맡았다는 거지.","JPN":"問題はあちら側でジャックの死について嗅ぎつけたことだ。","ENG":"The problem is the rebels have caught on to Jacques’ death.","TWN":"但現在問題是對方發現札克已經死亡，"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"분명 그 부분을 추궁할 테고……. 희생양이라도 넘겨 줘야 얘기가 원만하게 진행될 거다.","JPN":"きっとその点を問いただしてくるはず……人柱でも渡さないかぎり、話は円滑に進まないだろう。","ENG":"They will have questions. Things will only proceed smoothly if the culprit is handed over.","TWN":"對方肯定會追問這件事……勢必要有個人出來背黑鍋，後續才有可能談得下去。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"반군들이에요, 국장님! 말만 온건파지 똑같이 죽어 마땅한 쓰레기들이라고!","JPN":"反乱軍ですよ、局長！　穏健派を名乗ってるだけで、同じく死んで当然なクズどもよ！","ENG":"These are the rebels we’re talking about, Chief! They call themselves moderates but those bastards deserve to die all the same!\\n","TWN":"部長！那些叛軍表面上分什麼強硬派和溫和派，但骨子裡都一樣是該死的垃圾！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우리 엄마가 쓴 곡을 그 개자식들이 알아듣기나 할 것 같아?!","JPN":"お母さんが書いた曲の意味を、あのクソ野郎どもにわかると思う！？","ENG":"Do you think those scum could even comprehend the song my mom wrote?","TWN":"你覺得垃圾聽得懂我媽的曲子嗎？！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……상부에서 그러더군. 이 곡은 우리나라를 바꿀 수 있을 거라고.","JPN":"……上層部はこう言っていた。この曲はこの国を変えられると。","ENG":"...So our superiors believe. They believe this song has the power to change the country.","TWN":"……上面是這麼說的，這首曲子可以改變我們的國家。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L26_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그런 사이비 같은 허무맹랑한 말을 믿을 만큼, 이 나라는 쇠약해졌어.","JPN":"そんな新興宗教のようなでたらめを信じるほど、この国は衰えてしまった。","ENG":"This country has declined to the point where they believe in such nonsensical stuff like that.","TWN":"我們的國家已經衰敗到相信這種荒謬的言論。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뻔뻔스럽게……. 어떻게 그딴 소리를……!","JPN":"図々しい……よくもそんなことを……！","ENG":"How could you say something like that... so shamelessly...?","TWN":"真是厚顏無恥……怎麼說得出那種話……！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"국장님, 죄송합니다. 잠시 위로 올라와 보셔야겠습니다.","JPN":"局長、申し訳ありません。少々よろしいでしょうか。","ENG":"Apologies, Chief. You are needed up above.","TWN":"抱歉，可以請部長上去一趟嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐지? 급한 일인가?","JPN":"何だ？　急用か？","ENG":"What is it? Something urgent?","TWN":"有什麼急事嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"예. 그것이…….","JPN":"はい。それが……","ENG":"Yes sir, it’s...","TWN":"是，那個……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"알겠다. 첩보국에 지난번 획득한 물품을 준비해 두라고 해.","JPN":"わかった。諜報局に先日入手した品を用意しておくよう伝えてくれ。","ENG":"Very well. Tell Secret Service to prepare the items they’ve retrieved.","TWN":"好，吩咐下去，把上次情報局拿到的東西準備好。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"급한 용무가 생겼군. 심문은 잠시 미뤄 두지.","JPN":"急用ができた。尋問は後で再開しよう。","ENG":"I have some business to attend to. We shall continue this interrogation later.","TWN":"我現在有急事，等一下再繼續審問你。 "},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"잘 생각해 보게. 평화를 얻을 기회는 아직 자네 손에 남아 있어.","JPN":"よく考えてみてくれ。平和を手に入れるチャンスはまだ君の手の中に残っているんだ。","ENG":"Think carefully. The chance for peace is in your hands.","TWN":"你好好想想，取得和平的機會就掌握在你手裡。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};